
"use client";

import { useState, useEffect, useTransition } from 'react';
import { useSearchParams } from 'next/navigation';
import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle, Trash2, ArrowLeft, Loader2 } from 'lucide-react';
import Link from 'next/link';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { getMenusByVendorId, addMenuItem, deleteMenuItem, type MenuItem } from '@/ai/flows/menu-flow';

export default function MenuAdminPage({ params }: { params: { vendorId: string } }) {
  const { vendorId } = params;
  const searchParams = useSearchParams();
  const vendorName = searchParams.get('name') || '店家';
  const { toast } = useToast();

  const [menu, setMenu] = useState<MenuItem[]>([]);
  const [newItemName, setNewItemName] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  
  const [isLoading, setIsLoading] = useState(true);
  const [isPending, startTransition] = useTransition();


  const fetchMenu = async () => {
    setIsLoading(true);
    try {
      const fetchedMenu = await getMenusByVendorId(vendorId);
      setMenu(fetchedMenu);
    } catch (error) {
      console.error("讀取菜單失敗:", error);
      toast({ variant: "destructive", title: "讀取菜單失敗", description: "無法從 Google Sheet 讀取菜單。" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchMenu();
  }, [vendorId]);

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemName.trim() || !newItemPrice.trim()) {
      toast({ variant: "destructive", title: "請輸入品項名稱和價格" });
      return;
    }
    
    const price = parseInt(newItemPrice, 10);
    if (isNaN(price) || price <= 0) {
      toast({ variant: "destructive", title: "請輸入有效的價格" });
      return;
    }
    
    startTransition(async () => {
      try {
        await addMenuItem({ vendorId, name: newItemName, price });
        toast({ title: "品項已新增", description: `${newItemName} 已成功新增到菜單。` });
        setNewItemName('');
        setNewItemPrice('');
        await fetchMenu(); // Refresh list
      } catch (error) {
         toast({ variant: "destructive", title: "新增失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };
  
  const handleDeleteItem = (itemId: string, itemName: string) => {
    startTransition(async () => {
      try {
        await deleteMenuItem({ id: itemId });
        toast({ title: "品項已刪除", description: `${itemName} 已從菜單移除。`});
        await fetchMenu(); // Refresh list
      } catch (error) {
        toast({ variant: "destructive", title: "刪除失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="mb-6">
            <Link href="/admin" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground">
                <ArrowLeft className="h-4 w-4" />
                返回店家列表
            </Link>
        </div>
        <h1 className="font-headline text-3xl font-bold mb-2">編輯菜單：{decodeURIComponent(vendorName)}</h1>
        <p className="text-muted-foreground mb-6">管理 {decodeURIComponent(vendorName)} 的菜單品項。</p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Add New Item */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <PlusCircle className="h-6 w-6" />
                  <span>新增菜單品項</span>
                </CardTitle>
                <CardDescription>為 {decodeURIComponent(vendorName)} 加入新的餐點。</CardDescription>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleAddItem} className="space-y-4">
                  <Input 
                    placeholder="品項名稱 (例如: 雞腿飯)" 
                    value={newItemName}
                    onChange={(e) => setNewItemName(e.target.value)}
                    disabled={isPending}
                  />
                  <Input 
                    type="number"
                    placeholder="價格" 
                    value={newItemPrice}
                    onChange={(e) => setNewItemPrice(e.target.value)}
                    disabled={isPending}
                  />
                  <Button type="submit" className="w-full" disabled={isPending}>
                    {isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> 新增中...</> : '新增品項'}
                  </Button>
                </form>
              </CardContent>
            </Card>
          </section>
          
          {/* Menu Item List */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle>現有品項</CardTitle>
                <CardDescription>管理目前的菜單品項。</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {isLoading ? (
                  <div className="flex justify-center items-center py-4">
                    <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                    <p className="ml-2 text-muted-foreground">讀取中...</p>
                  </div>
                ) : menu.length > 0 ? (
                  menu.map(item => (
                    <Card key={item.id} className="p-3 flex justify-between items-center">
                      <div>
                        <p className="font-semibold">{item.name}</p>
                        <p className="text-sm text-muted-foreground">${item.price}</p>
                      </div>
                      <AlertDialog>
                          <AlertDialogTrigger asChild>
                              <Button variant="ghost" size="icon" aria-label={`刪除 ${item.name}`} disabled={isPending}>
                                  <Trash2 className="h-4 w-4 text-destructive" />
                              </Button>
                          </AlertDialogTrigger>
                          <AlertDialogContent>
                              <AlertDialogHeader>
                                  <AlertDialogTitle>確定要刪除品項嗎？</AlertDialogTitle>
                                  <AlertDialogDescription>
                                      此動作無法復原。這將會永久刪除菜單品項「{item.name}」。
                                  </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                  <AlertDialogCancel>取消</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => handleDeleteItem(item.id, item.name)} disabled={isPending}>確定刪除</AlertDialogAction>
                              </AlertDialogFooter>
                          </AlertDialogContent>
                      </AlertDialog>
                    </Card>
                  ))
                ) : (
                  <p className="text-sm text-center text-muted-foreground py-4">這個店家還沒有任何菜單品項。</p>
                )}
              </CardContent>
            </Card>
          </section>
        </div>
      </main>
    </div>
  );
}
