
'use server';
/**
 * @fileOverview Flow for handling menu data from Google Sheets.
 */
import { getSheetData, appendSheetData, clearSheetData } from '@/services/sheet-service';
import { z } from 'zod';

// The ID of your Google Sheet
const SPREADSHEET_ID = '1Zj2h0cYlrb2mBaNgl1-PoOK7tlCCwDccAXn5w66hp4c';
const MENU_SHEET_NAME = 'menus';

export type MenuItem = {
  id: string;
  vendorId: string;
  name: string;
  price: number;
  isActive: boolean;
};

/**
 * Retrieves all menu items for a given vendor from the 'menus' sheet.
 * @param {string} vendorId The ID of the vendor.
 * @returns {Promise<MenuItem[]>} A list of menu items.
 */
export async function getMenusByVendorId(vendorId: string): Promise<MenuItem[]> {
  try {
    const range = `${MENU_SHEET_NAME}!A2:E`; // Assuming row 1 is headers
    const data = await getSheetData(SPREADSHEET_ID, range);

    if (!data || data.length === 0) {
      return [];
    }

    const allItems = data.map((row, index) => ({
      rowNumber: index + 2, // Keep track of original row number for deletion
      id: row[0] || '',
      vendorId: row[1] || '',
      name: row[2] || '',
      price: parseInt(row[3] || '0', 10),
      isActive: row[4] === 'TRUE',
    }));
    
    return allItems
      .filter(item => item.vendorId === vendorId && item.isActive)
      .map(({rowNumber, ...item}) => item); // Filter by vendor and active status

  } catch (error) {
    console.error("讀取菜單失敗:", error);
    // Return empty array on error to prevent page crash
    return [];
  }
}

export type AddMenuItemRequest = {
  vendorId: string;
  name: string;
  price: number;
};

/**
 * Adds a new menu item to the 'menus' sheet.
 * @param {AddMenuItemRequest} item - The menu item data to add.
 * @returns {Promise<{success: boolean}>} A success flag.
 */
export async function addMenuItem(item: AddMenuItemRequest): Promise<{ success: boolean }> {
  const AddMenuItemSchema = z.object({
    vendorId: z.string(),
    name: z.string().min(1, "品項名稱不能為空"),
    price: z.number().positive("價格必須是正數"),
  });

  const validation = AddMenuItemSchema.safeParse(item);
  if (!validation.success) {
      const a = validation.error.format()._errors.join(', ');
      throw new Error(`輸入資料有誤: ${a}`);
  }

  const range = `${MENU_SHEET_NAME}!A:E`;
  const allMenusRange = `${MENU_SHEET_NAME}!A2:A`;
  
  const allMenuIdsData = await getSheetData(SPREADSHEET_ID, allMenusRange);
  const lastIdNum = allMenuIdsData.length > 0 
      ? Math.max(...allMenuIdsData.map(row => parseInt((row[0] || 'm0').replace('m', ''), 10)))
      : 0;

  const newId = `m${(lastIdNum + 1).toString().padStart(3, '0')}`;
  
  const values = [
    [newId, item.vendorId, item.name, item.price, 'TRUE'],
  ];

  await appendSheetData(SPREADSHEET_ID, range, values);
  return { success: true };
}

export type DeleteMenuItemRequest = {
    id: string;
};

/**
 * Deletes a menu item from the 'menus' sheet by its ID.
 * @param {DeleteMenuItemRequest} req - The request containing the item ID to delete.
 * @returns {Promise<{success: boolean}>} A success flag.
 */
export async function deleteMenuItem(req: DeleteMenuItemRequest): Promise<{ success: boolean }> {
    const range = `${MENU_SHEET_NAME}!A2:E`;
    const data = await getSheetData(SPREADSHEET_ID, range);

    if (!data) {
        throw new Error("找不到菜單資料。");
    }
    
    const rowIndex = data.findIndex(row => row[0] === req.id);
    
    if (rowIndex === -1) {
        console.log(`找不到 ID 為 ${req.id} 的菜單品項。`);
        return { success: false }; // Item not found
    }

    // Google Sheets API row indices are 1-based. Sheet data starts from row 2.
    const rowToDelete = rowIndex + 2; 
    const clearRange = `${MENU_SHEET_NAME}!A${rowToDelete}:E${rowToDelete}`;

    await clearSheetData(SPREADSHEET_ID, clearRange);
    
    return { success: true };
}
